"use strict";(globalThis.webpackChunk_uniswap_docs=globalThis.webpackChunk_uniswap_docs||[]).push([[76490],{28453:(e,n,a)=>{a.d(n,{R:()=>r,x:()=>i});var t=a(96540);const o={},s=t.createContext(o);function r(e){const n=t.useContext(s);return t.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function i(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:r(e.components),t.createElement(s.Provider,{value:n},e.children)}},99662:(e,n,a)=>{a.r(n),a.d(n,{assets:()=>l,contentTitle:()=>i,default:()=>p,frontMatter:()=>r,metadata:()=>t,toc:()=>d});const t=JSON.parse('{"id":"contracts/v3/guides/flash-integrations/final-contract","title":"The Final Contract","description":"The Full Contract","source":"@site/docs/contracts/v3/guides/flash-integrations/final-contract.md","sourceDirName":"contracts/v3/guides/flash-integrations","slug":"/contracts/v3/guides/flash-integrations/final-contract","permalink":"/contracts/v3/guides/flash-integrations/final-contract","draft":false,"unlisted":false,"editUrl":"https://github.com/uniswap/uniswap-docs/tree/main/docs/contracts/v3/guides/flash-integrations/final-contract.md","tags":[],"version":"current","sidebarPosition":4,"frontMatter":{"id":"final-contract","title":"The Final Contract","sidebar_position":4},"sidebar":"main","previous":{"title":"The Flash Callback","permalink":"/contracts/v3/guides/flash-integrations/flash-callback"},"next":{"title":"License Modifications","permalink":"/contracts/v3/guides/governance/license-modifications"}}');var o=a(74848),s=a(28453);const r={id:"final-contract",title:"The Final Contract",sidebar_position:4},i=void 0,l={},d=[{value:"The Full Contract",id:"the-full-contract",level:2}];function c(e){const n={code:"code",h2:"h2",pre:"pre",...(0,s.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.h2,{id:"the-full-contract",children:"The Full Contract"}),"\n",(0,o.jsx)(n.pre,{children:(0,o.jsx)(n.code,{className:"language-solidity",children:"// SPDX-License-Identifier: GPL-2.0-or-later\npragma solidity =0.7.6;\npragma abicoder v2;\n\nimport '@uniswap/v3-core/contracts/interfaces/callback/IUniswapV3FlashCallback.sol';\nimport '@uniswap/v3-core/contracts/libraries/LowGasSafeMath.sol';\n\nimport '@uniswap/v3-periphery/contracts/base/PeripheryPayments.sol';\nimport '@uniswap/v3-periphery/contracts/base/PeripheryImmutableState.sol';\nimport '@uniswap/v3-periphery/contracts/libraries/PoolAddress.sol';\nimport '@uniswap/v3-periphery/contracts/libraries/CallbackValidation.sol';\nimport '@uniswap/v3-periphery/contracts/libraries/TransferHelper.sol';\nimport '@uniswap/v3-periphery/contracts/interfaces/ISwapRouter.sol';\n\n/// @title Flash contract implementation\n/// @notice An example contract using the Uniswap V3 flash function\ncontract PairFlash is IUniswapV3FlashCallback, PeripheryImmutableState, PeripheryPayments {\n    using LowGasSafeMath for uint256;\n    using LowGasSafeMath for int256;\n\n    ISwapRouter public immutable swapRouter;\n\n    constructor(\n        ISwapRouter _swapRouter,\n        address _factory,\n        address _WETH9\n    ) PeripheryImmutableState(_factory, _WETH9) {\n        swapRouter = _swapRouter;\n    }\n\n    /// @param fee0 The fee from calling flash for token0\n    /// @param fee1 The fee from calling flash for token1\n    /// @param data The data needed in the callback passed as FlashCallbackData from `initFlash`\n    /// @notice implements the callback called from flash\n    /// @dev fails if the flash is not profitable, meaning the amountOut from the flash is less than the amount borrowed\n    function uniswapV3FlashCallback(\n        uint256 fee0,\n        uint256 fee1,\n        bytes calldata data\n    ) external override {\n        FlashCallbackData memory decoded = abi.decode(data, (FlashCallbackData));\n        CallbackValidation.verifyCallback(factory, decoded.poolKey);\n\n        address token0 = decoded.poolKey.token0;\n        address token1 = decoded.poolKey.token1;\n\n        TransferHelper.safeApprove(token0, address(swapRouter), decoded.amount0);\n        TransferHelper.safeApprove(token1, address(swapRouter), decoded.amount1);\n\n        // profitable check\n        // exactInputSingle will fail if this amount not met\n        uint256 amount1Min = LowGasSafeMath.add(decoded.amount1, fee1);\n        uint256 amount0Min = LowGasSafeMath.add(decoded.amount0, fee0);\n\n        // call exactInputSingle for swapping token1 for token0 in pool w/fee2\n        uint256 amountOut0 =\n            swapRouter.exactInputSingle(\n                ISwapRouter.ExactInputSingleParams({\n                    tokenIn: token1,\n                    tokenOut: token0,\n                    fee: decoded.poolFee2,\n                    recipient: address(this),\n                    deadline: block.timestamp,\n                    amountIn: decoded.amount1,\n                    amountOutMinimum: amount0Min,\n                    sqrtPriceLimitX96: 0\n                })\n            );\n\n        // call exactInputSingle for swapping token0 for token 1 in pool w/fee3\n        uint256 amountOut1 =\n            swapRouter.exactInputSingle(\n                ISwapRouter.ExactInputSingleParams({\n                    tokenIn: token0,\n                    tokenOut: token1,\n                    fee: decoded.poolFee3,\n                    recipient: address(this),\n                    deadline: block.timestamp,\n                    amountIn: decoded.amount0,\n                    amountOutMinimum: amount1Min,\n                    sqrtPriceLimitX96: 0\n                })\n            );\n\n        // end up with amountOut0 of token0 from first swap and amountOut1 of token1 from second swap\n        uint256 amount0Owed = LowGasSafeMath.add(decoded.amount0, fee0);\n        uint256 amount1Owed = LowGasSafeMath.add(decoded.amount1, fee1);\n\n        TransferHelper.safeApprove(token0, address(this), amount0Owed);\n        TransferHelper.safeApprove(token1, address(this), amount1Owed);\n\n        if (amount0Owed > 0) pay(token0, address(this), msg.sender, amount0Owed);\n        if (amount1Owed > 0) pay(token1, address(this), msg.sender, amount1Owed);\n\n        // if profitable pay profits to payer\n        if (amountOut0 > amount0Owed) {\n            uint256 profit0 = LowGasSafeMath.sub(amountOut0, amount0Owed);\n\n            TransferHelper.safeApprove(token0, address(this), profit0);\n            pay(token0, address(this), decoded.payer, profit0);\n        }\n        if (amountOut1 > amount1Owed) {\n            uint256 profit1 = LowGasSafeMath.sub(amountOut1, amount1Owed);\n            TransferHelper.safeApprove(token0, address(this), profit1);\n            pay(token1, address(this), decoded.payer, profit1);\n        }\n    }\n\n    //fee1 is the fee of the pool from the initial borrow\n    //fee2 is the fee of the first pool to arb from\n    //fee3 is the fee of the second pool to arb from\n    struct FlashParams {\n        address token0;\n        address token1;\n        uint24 fee1;\n        uint256 amount0;\n        uint256 amount1;\n        uint24 fee2;\n        uint24 fee3;\n    }\n    // fee2 and fee3 are the two other fees associated with the two other pools of token0 and token1\n    struct FlashCallbackData {\n        uint256 amount0;\n        uint256 amount1;\n        address payer;\n        PoolAddress.PoolKey poolKey;\n        uint24 poolFee2;\n        uint24 poolFee3;\n    }\n\n    /// @param params The parameters necessary for flash and the callback, passed in as FlashParams\n    /// @notice Calls the pools flash function with data needed in `uniswapV3FlashCallback`\n    function initFlash(FlashParams memory params) external {\n        PoolAddress.PoolKey memory poolKey =\n            PoolAddress.PoolKey({token0: params.token0, token1: params.token1, fee: params.fee1});\n        IUniswapV3Pool pool = IUniswapV3Pool(PoolAddress.computeAddress(factory, poolKey));\n        // recipient of borrowed amounts\n        // amount of token0 requested to borrow\n        // amount of token1 requested to borrow\n        // need amount 0 and amount1 in callback to pay back pool\n        // recipient of flash should be THIS contract\n        pool.flash(\n            address(this),\n            params.amount0,\n            params.amount1,\n            abi.encode(\n                FlashCallbackData({\n                    amount0: params.amount0,\n                    amount1: params.amount1,\n                    payer: msg.sender,\n                    poolKey: poolKey,\n                    poolFee2: params.fee2,\n                    poolFee3: params.fee3\n                })\n            )\n        );\n    }\n}\n\n"})})]})}function p(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(c,{...e})}):c(e)}}}]);